@@ -81,11 +81,11 @@ sync_toml_mcp_url() {
   # If the section already has a `command = ...` entry (stdio transport),
   # injecting `url = ...` would corrupt a working config. Skip entirely.
   if awk '
-    BEGIN { in_section = 0 }
+    BEGIN { in_section = 0; found = 0 }
     /^\[mcp_servers\.mcp_agent_mail\]/ || /^\[mcp_servers\."mcp-agent-mail"\]/ { in_section = 1; next }
     /^\[/ { in_section = 0 }
-    in_section && /^[[:space:]]*command[[:space:]]*=/ { exit 0 }
-    END { exit 1 }
+    in_section && /^[[:space:]]*command[[:space:]]*=/ { found = 1 }
+    END { exit (found ? 0 : 1) }
   ' "$config_file" 2>/dev/null; then
     return 0
   fi
